/**
 * DataTableFilter
 * ===============
 * Reusable filter component for data tables
 * Supports various field types with appropriate filter UIs
 */

import React from "react";
import type { MetaField } from "@afenda/meta-types";
import type { FilterCondition, FilterGroup } from "~/hooks/useModel";
import { 
  Button,
  Input,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Popover,
  PopoverContent,
  PopoverTrigger,
  Badge,
} from "@afenda/ui";
import { Filter, X, Plus } from "lucide-react";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface DataTableFilterProps {
  fields: MetaField[];
  value: FilterGroup;
  onChange: (newValue: FilterGroup) => void;
}

const OPERATORS = {
  string: [
    { value: "eq", label: "equals" },
    { value: "neq", label: "not equals" },
    { value: "like", label: "contains" },
    { value: "ilike", label: "contains (case-insensitive)" },
    { value: "is_null", label: "is empty" },
    { value: "is_not_null", label: "is not empty" },
  ],
  number: [
    { value: "eq", label: "equals" },
    { value: "neq", label: "not equals" },
    { value: "gt", label: "greater than" },
    { value: "gte", label: "greater than or equal" },
    { value: "lt", label: "less than" },
    { value: "lte", label: "less than or equal" },
    { value: "is_null", label: "is empty" },
    { value: "is_not_null", label: "is not empty" },
  ],
  boolean: [
    { value: "eq", label: "equals" },
  ],
  enum: [
    { value: "eq", label: "equals" },
    { value: "neq", label: "not equals" },
    { value: "in", label: "is one of" },
  ],
};

function getOperatorsForField(field: MetaField) {
  if (field.type === "boolean") return OPERATORS.boolean;
  if (field.type === "enum") return OPERATORS.enum;
  if (["integer", "decimal", "currency"].includes(field.type)) return OPERATORS.number;
  return OPERATORS.string;
}

function needsValue(op: string): boolean {
  return !["is_null", "is_not_null"].includes(op);
}

// ---------------------------------------------------------------------------
// FilterConditionRow
// ---------------------------------------------------------------------------

interface FilterConditionRowProps {
  fields: MetaField[];
  condition: FilterCondition;
  onChange: (newCondition: FilterCondition) => void;
  onRemove: () => void;
}

function FilterConditionRow({ fields, condition, onChange, onRemove }: FilterConditionRowProps) {
  const selectedField = fields.find((f) => f.name === condition.field);
  const operators = selectedField ? getOperatorsForField(selectedField) : OPERATORS.string;
  const showValueInput = needsValue(condition.op);

  return (
    <div className="flex items-center gap-2 mb-2">
      {/* Field selector */}
      <Select
        value={condition.field}
        onValueChange={(field) => onChange({ ...condition, field, value: undefined })}
      >
        <SelectTrigger className="w-[180px]">
          <SelectValue placeholder="Select field" />
        </SelectTrigger>
        <SelectContent>
          {fields.map((field) => (
            <SelectItem key={field.name} value={field.name}>
              {field.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Operator selector */}
      <Select
        value={condition.op}
        onValueChange={(op) => onChange({ ...condition, op: op as FilterCondition['op'] })}
      >
        <SelectTrigger className="w-[200px]">
          <SelectValue />
        </SelectTrigger>
        <SelectContent>
          {operators.map((op) => (
            <SelectItem key={op.value} value={op.value}>
              {op.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Value input (conditional) */}
      {showValueInput && selectedField && (
        <>
          {selectedField.type === "boolean" ? (
            <Select
              value={String(condition.value ?? "true")}
              onValueChange={(val) => onChange({ ...condition, value: val === "true" })}
            >
              <SelectTrigger className="w-[150px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="true">Yes</SelectItem>
                <SelectItem value="false">No</SelectItem>
              </SelectContent>
            </Select>
          ) : selectedField.type === "enum" && selectedField.options ? (
            condition.op === "in" ? (
              <Input
                type="text"
                placeholder="Values (comma-separated)"
                value={Array.isArray(condition.value) ? condition.value.join(", ") : ""}
                onChange={(e) => {
                  const values = e.target.value.split(",").map((v) => v.trim()).filter(Boolean);
                  onChange({ ...condition, value: values });
                }}
                className="flex-1"
              />
            ) : (
              <Select
                value={String(condition.value ?? "")}
                onValueChange={(val) => onChange({ ...condition, value: val })}
              >
                <SelectTrigger className="flex-1">
                  <SelectValue placeholder="Select value" />
                </SelectTrigger>
                <SelectContent>
                  {selectedField.options.map((opt) => (
                    <SelectItem key={opt.value} value={String(opt.value)}>
                      {opt.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            )
          ) : (
            <Input
              type={
                ["integer", "decimal", "currency"].includes(selectedField.type) ? "number" : "text"
              }
              placeholder={condition.op === "like" || condition.op === "ilike" ? "Search..." : "Value"}
              value={String(condition.value ?? "")}
              onChange={(e) => {
                const val = ["integer", "decimal", "currency"].includes(selectedField.type)
                  ? Number(e.target.value)
                  : condition.op === "like" || condition.op === "ilike"
                  ? `%${e.target.value}%`
                  : e.target.value;
                onChange({ ...condition, value: val });
              }}
              className="flex-1"
            />
          )}
        </>
      )}

      {/* Remove button */}
      <Button
        variant="ghost"
        size="icon"
        onClick={onRemove}
        className="shrink-0"
      >
        <X className="h-4 w-4" />
      </Button>
    </div>
  );
}

// ---------------------------------------------------------------------------
// DataTableFilter
// ---------------------------------------------------------------------------

export function DataTableFilter({ fields, value, onChange }: DataTableFilterProps) {
  const [open, setOpen] = React.useState(false);
  const activeFiltersCount = value.conditions.length;

  const handleAddCondition = () => {
    const firstField = fields[0];
    if (!firstField) return;

    onChange({
      ...value,
      conditions: [
        ...value.conditions,
        { field: firstField.name, op: "eq", value: undefined },
      ],
    });
  };

  const handleUpdateCondition = (index: number, condition: FilterCondition) => {
    const newConditions = [...value.conditions];
    newConditions[index] = condition;
    onChange({ ...value, conditions: newConditions });
  };

  const handleRemoveCondition = (index: number) => {
    onChange({
      ...value,
      conditions: value.conditions.filter((_, i) => i !== index),
    });
  };

  const handleClearAll = () => {
    onChange({ ...value, conditions: [] });
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" className="relative">
          <Filter className="mr-2 h-4 w-4" />
          Filter
          {activeFiltersCount > 0 && (
            <Badge variant="secondary" className="ml-2 h-5 px-1.5">
              {activeFiltersCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[600px]" align="start">
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h4 className="text-sm font-semibold">Filters</h4>
            {activeFiltersCount > 0 && (
              <Button
                variant="ghost"
                size="sm"
                onClick={handleClearAll}
              >
                Clear all
              </Button>
            )}
          </div>

          {value.conditions.length === 0 ? (
            <div className="text-sm text-muted-foreground py-4 text-center">
              No filters applied
            </div>
          ) : (
            <div>
              {value.conditions.map((condition, index) => (
                <FilterConditionRow
                  key={index}
                  fields={fields}
                  condition={condition}
                  onChange={(cond) => handleUpdateCondition(index, cond)}
                  onRemove={() => handleRemoveCondition(index)}
                />
              ))}
            </div>
          )}

          <Button
            variant="outline"
            size="sm"
            onClick={handleAddCondition}
            className="w-full"
          >
            <Plus className="mr-2 h-4 w-4" />
            Add filter
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  );
}
