/**
 * MetaListV2 - Enterprise Edition
 * ================================
 * Production-grade data table with:
 * • @tanstack/react-table for column management, sorting, filtering
 * • shadcn/ui Table components
 * • Column visibility toggle
 * • Server-side pagination & sorting
 * • Loading skeletons & empty states
 * • Row selection (optional)
 */

import React, { useCallback, useMemo } from "react";
import {
  type ColumnDef,
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  type SortingState,
  useReactTable,
  type VisibilityState,
} from "@tanstack/react-table";
import type { MetaListView, MetaField } from "@afenda/meta-types";
import { useMeta } from "~/hooks/useMeta";
import { useModelList, type FilterGroup } from "~/hooks/useModel";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@afenda/ui";
import { Button } from "@afenda/ui";
import { Skeleton } from "@afenda/ui";
import { PageHeader, PageContainer, DataCard } from "~/components/layout";
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@afenda/ui";
import { 
  ChevronLeft, 
  ChevronRight, 
  ChevronsLeft, 
  ChevronsRight,
  ArrowUpDown,
  ArrowUp,
  ArrowDown,
  Settings2,
  Plus,
} from "lucide-react";
import { Badge } from "@afenda/ui";
import { DataTableFilter } from "~/components/filters/DataTableFilter";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface MetaListV2Props {
  model: string;
  onRowClick?: (rec: Record<string, unknown>) => void;
  onNew?: () => void;
  embedded?: boolean;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function formatCellValue(value: unknown, field: MetaField): React.ReactNode {
  if (value == null) return <span className="text-muted-foreground">—</span>;
  
  switch (field.type) {
    case "boolean":
      return value ? (
        <Badge variant="secondary">Yes</Badge>
      ) : (
        <Badge variant="outline">No</Badge>
      );
    
    case "date":
      if (typeof value === "string") {
        return new Date(value).toLocaleDateString();
      }
      break;
    
    case "datetime":
      if (typeof value === "string") {
        return new Date(value).toLocaleString();
      }
      break;
    
    case "enum":
      if (field.options) {
        const opt = field.options.find((o) => o.value === value);
        if (opt) {
          return (
            <Badge variant="secondary" style={{ backgroundColor: opt.color }}>
              {opt.label}
            </Badge>
          );
        }
      }
      break;
    
    case "currency":
      if (typeof value === "number") {
        return new Intl.NumberFormat("en-US", {
          style: "currency",
          currency: "USD",
        }).format(value);
      }
      break;
  }
  
  return String(value);
}

// Generate columns from MetaListView
function generateColumns(
  columnNames: string[],
  fieldMap: Map<string, MetaField>,
  onRowClick?: (rec: Record<string, unknown>) => void
): ColumnDef<Record<string, unknown>>[] {
  return columnNames.map((colName) => {
    const field = fieldMap.get(colName);
    
    return {
      accessorKey: colName,
      header: ({ column }) => {
        const isSorted = column.getIsSorted();
        const canSort = field?.sortable !== false;
        
        if (!canSort) {
          return <div>{field?.label ?? colName}</div>;
        }
        
        return (
          <Button
            variant="ghost"
            onClick={() => column.toggleSorting(column.getIsSorted() === "asc")}
            className="-ml-4 h-8"
          >
            {field?.label ?? colName}
            {isSorted === "asc" ? (
              <ArrowUp className="ml-2 h-4 w-4" />
            ) : isSorted === "desc" ? (
              <ArrowDown className="ml-2 h-4 w-4" />
            ) : (
              <ArrowUpDown className="ml-2 h-4 w-4 opacity-50" />
            )}
          </Button>
        );
      },
      cell: ({ row, getValue }) => {
        const value = getValue();
        const formatted = field ? formatCellValue(value, field) : String(value ?? "—");
        
        return (
          <div 
            className={onRowClick ? "cursor-pointer" : ""}
            onClick={(e) => {
              e.stopPropagation();
              onRowClick?.(row.original);
            }}
          >
            {formatted}
          </div>
        );
      },
    };
  });
}

// ---------------------------------------------------------------------------
// Sub-Components
// ---------------------------------------------------------------------------

function TableSkeleton({ columns }: { columns: number }) {
  return (
    <div className="space-y-3">
      {Array.from({ length: 8 }).map((_, i) => (
        <div key={i} className="flex gap-4">
          {Array.from({ length: columns }).map((_, j) => (
            <Skeleton key={j} className="h-10 flex-1" />
          ))}
        </div>
      ))}
    </div>
  );
}

function EmptyState({ onNew, canCreate }: { onNew?: () => void; canCreate: boolean }) {
  return (
    <div className="flex flex-col items-center justify-center py-16 text-center">
      <div className="rounded-full bg-muted p-4 mb-4">
        <Settings2 className="h-8 w-8 text-muted-foreground" />
      </div>
      <h3 className="text-lg font-semibold mb-2">No records found</h3>
      <p className="text-sm text-muted-foreground mb-6">
        {canCreate ? "Get started by creating your first record." : "There are no records to display."}
      </p>
      {canCreate && onNew && (
        <Button onClick={onNew}>
          <Plus className="mr-2 h-4 w-4" />
          Create Record
        </Button>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// MetaListV2
// ---------------------------------------------------------------------------

export function MetaListV2({ 
  model, 
  onRowClick, 
  onNew, 
  embedded = false 
}: MetaListV2Props) {
  const [page, setPage] = React.useState(1);
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
  const [filters, setFilters] = React.useState<FilterGroup>({ logic: "and", conditions: [] });
  
  const pageSize = 20;

  // Fetch metadata
  const { data: metaResponse, isLoading: metaLoading } = useMeta(model);
  const meta = metaResponse?.meta;
  const listView = meta?.views?.list as MetaListView | undefined;
  const permissions = metaResponse?.permissions;

  // Derive sort params for API
  const sortField = sorting[0]?.id;
  const sortDir = sorting[0]?.desc ? "desc" : "asc";

  // Fetch data with filters
  const { data, isLoading: listLoading } = useModelList(model, {
    page,
    limit: pageSize,
    orderBy: sortField,
    orderDir: sortDir as "asc" | "desc",
    filters: filters.conditions.length > 0 ? filters : undefined,
  });

  const rows = data?.data ?? [];
  const totalRecords = data?.meta?.total ?? 0;
  const totalPages = Math.ceil(totalRecords / pageSize);

  // Reset to page 1 when filters change
  React.useEffect(() => {
    setPage(1);
  }, [filters]);

  // Build columns
  const fieldMap = useMemo(
    () => new Map(meta?.fields.map((f) => [f.name, f]) ?? []),
    [meta?.fields]
  );

  const handleRowClick = useCallback(
    (record: Record<string, unknown>) => {
      onRowClick?.(record);
    },
    [onRowClick]
  );

  const handleFiltersChange = useCallback(
    (newFilters: FilterGroup) => {
      setFilters(newFilters);
    },
    []
  );

  const columns = useMemo(
    () => {
      if (!listView) return [];
      return generateColumns(listView.columns, fieldMap, handleRowClick);
    },
    [listView, fieldMap, handleRowClick]
  );

  // Initialize table
  const table = useReactTable({
    data: rows,
    columns,
    state: {
      sorting,
      columnVisibility,
    },
    onSortingChange: setSorting,
    onColumnVisibilityChange: setColumnVisibility,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    manualSorting: true,
    manualPagination: true,
    pageCount: totalPages,
  });

  // Loading state
  if (metaLoading || (listLoading && page === 1)) {
    if (embedded) return <TableSkeleton columns={listView?.columns.length ?? 3} />;
    return (
      <PageContainer>
        <PageHeader title="Loading..." />
        <DataCard>
          <TableSkeleton columns={listView?.columns.length ?? 3} />
        </DataCard>
      </PageContainer>
    );
  }

  // No meta
  if (!meta || !listView) {
    return (
      <PageContainer>
        <div className="text-muted-foreground">No list view configured for "{model}".</div>
      </PageContainer>
    );
  }

  const canCreate = permissions?.can_create ?? false;

  const tableContent = (
    <>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <DataTableFilter
            fields={meta?.fields ?? []}
            value={filters}
            onChange={handleFiltersChange}
          />
          
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="sm">
                <Settings2 className="mr-2 h-4 w-4" />
                Columns
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="start" className="w-48">
              {table.getAllColumns()
                .filter((column) => column.getCanHide())
                .map((column) => {
                  const field = fieldMap.get(column.id);
                  return (
                    <DropdownMenuCheckboxItem
                      key={column.id}
                      checked={column.getIsVisible()}
                      onCheckedChange={(value) => column.toggleVisibility(!!value)}
                    >
                      {field?.label ?? column.id}
                    </DropdownMenuCheckboxItem>
                  );
                })}
            </DropdownMenuContent>
          </DropdownMenu>
          
          <div className="text-sm text-muted-foreground">
            {totalRecords} {totalRecords === 1 ? "record" : "records"}
          </div>
        </div>

        {canCreate && onNew && (
          <Button onClick={onNew}>
            <Plus className="mr-2 h-4 w-4" />
            New
          </Button>
        )}
      </div>

      <div className="rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.length === 0 ? (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-64 text-center">
                  <EmptyState onNew={onNew} canCreate={canCreate} />
                </TableCell>
              </TableRow>
            ) : (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                  className={onRowClick ? "cursor-pointer" : ""}
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {totalPages > 1 && (
        <div className="flex items-center justify-between mt-4">
          <div className="text-sm text-muted-foreground">
            Page {page} of {totalPages}
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => setPage(1)}
              disabled={page === 1}
            >
              <ChevronsLeft className="h-4 w-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setPage(totalPages)}
              disabled={page === totalPages}
            >
              <ChevronsRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      )}
    </>
  );

  if (embedded) {
    return tableContent;
  }

  return (
    <PageContainer>
      <PageHeader
        title={meta.label_plural ?? meta.label}
        breadcrumbs={[
          { label: "Home", href: "/" },
          { label: meta.label_plural ?? meta.label },
        ]}
      />
      <DataCard>{tableContent}</DataCard>
    </PageContainer>
  );
}
